def timestampUTC = {
    def df = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss.S z")
    df.setTimeZone(TimeZone.getTimeZone("UTC"))
    df.format(new Date())
}

tasks.register("createProperties") {
    dependsOn(processResources)

    def propsFile = layout.buildDirectory.file("resources/main/web3j-version.properties")

    inputs.property("version", provider { project.version.toString() })
    outputs.file(propsFile)

    doLast {
        def outFile = propsFile.get().asFile
        outFile.parentFile.mkdirs()

        Properties p = new Properties()
        p["version"] = project.version.toString()
        p["timestamp"] = timestampUTC()

        outFile.withWriter("UTF-8") { w ->
            p.store(w, null)
        }
    }
}

